SELECT hospitals.name, grades.grade_name 
FROM hospitals 
JOIN grades ON hospitals.grade = grades.grade_id;

SELECT COUNT(DISTINCT hospital_id) 
FROM hospitals 
WHERE district = 'your_district_name_here';

SELECT *
FROM hospitals
WHERE district = 'Desired District Name';

SELECT DISTINCT single_multi AS hospital_type
FROM hospitals
WHERE district = 'Salem';

SELECT *
FROM hospitals
ORDER BY name ASC;

SELECT name, single_multi, bed_count 
FROM hospitals 
ORDER BY name;

SELECT directorate_name, head, contact_number, email
FROM directorates
WHERE directorate_name = 'DirectorateName';
